import fs from "node:fs";
import path from "node:path";

const root = process.cwd();
const excelPath = path.join(root, "excel-modded", "main.js");
const outDir = path.join(root, "src", "generated");
const outFile = path.join(outDir, "excelBundle.ts");

if (!fs.existsSync(excelPath)) {
  console.error("[comshit] Missing excel-modded/main.js — build cannot embed Excel.");
  process.exit(1);
}

const source = fs.readFileSync(excelPath, "utf8");
fs.mkdirSync(outDir, { recursive: true });
fs.writeFileSync(
  outFile,
  `// AUTO-GENERATED by scripts/generate-excel-bundle.mjs — do not edit.\nexport const EMBEDDED_EXCEL_MAIN: string = ${JSON.stringify(source)};\n`,
);
console.log(`[comshit] Wrote ${path.relative(root, outFile)} (${source.length} bytes from excel-modded/main.js)`);
